# coding: utf-8
import json
from typing import Optional, Union

import click
from tabulate import tabulate

from rainbow_admin.cli import err, info
from rainbow_admin.file import FileGroup
from rainbow_admin.group import BaseGroup
from rainbow_admin.kv import KVGroup
from rainbow_admin.table import TableGroup

GROUP_HEADER = (
    "id",
    "name",
    "create_time",
    "description",
    "group_type",
    "config_type",
    "omit_approval",
    "publish_type",
)
VERSION_HEADER = ("id", "name", "creator", "description", "create_time", "version_uuid")


def format_group(group: BaseGroup):
    return [
        group.group_id,
        group.group_name,
        group.create_time,
        group.description,
        group.infos["group_type"],
        group.config_type_str.lstrip("GROUPCONFIG_"),
        "Y" if group.omit_approval else "N",
        group.publish_type,
    ]


def get_group_by_id_or_name(
    admin, group_id_or_name
) -> Optional[Union[BaseGroup, KVGroup, TableGroup, FileGroup]]:
    if not group_id_or_name:
        err("group不能为空，请使用 -g 指定group，或设置 RAINBOW_GROUP 环境变量")
        return
    group = admin.get_group(group_id_or_name)
    if group is None:
        try:
            group_id_or_name = int(group_id_or_name)
        except ValueError:
            err(f"未找到名为{group_id_or_name}的配置组")
            return
        group = admin.get_group_by_id(group_id_or_name)
        if group is None:
            err(f"未找到名为{group_id_or_name}的配置组")
            return
    return group


@click.group(name="group")
def group_cli():
    """actions about group"""


@group_cli.command(help="list all group")
@click.pass_context
def ls(ctx):
    admin = ctx.obj["admin"]
    groups = admin.groups
    info(f"{admin.app_id} groups:")
    data = [format_group(i) for i in groups.values()]
    click.echo(tabulate(data, GROUP_HEADER, tablefmt="pretty"))


@group_cli.command("info", help="get group detail info")
@click.option(
    "-v", "--version", "version_id", default=0, type=int, help="0：当前分组配置, >0:对应版本分组信息"
)
@click.argument("group_id_or_name", required=True)
@click.pass_context
def group_info(ctx, group_id_or_name, version_id):
    admin = ctx.obj["admin"]
    group = get_group_by_id_or_name(admin, group_id_or_name)
    infos = group.get_info(version_id)
    info(
        f"app_id={admin.app_id}, group_id={group.group_id}, group_name={group.group_name} info:"
    )
    info("group info:")
    click.echo(tabulate(infos["group_info"].items(), tablefmt="simple"))
    click.echo()
    info("version info:")
    click.echo(tabulate(infos["version_info"].items(), tablefmt="simple"))
    click.echo()
    related_groups = group.related_groups
    if related_groups:
        info("related info:")
        if group.is_public:
            related_groups = [
                (
                    i["group_id"],
                    i["group_name"],
                    i["description"],
                    "是" if i["is_lastest"] else "否",
                )
                for i in related_groups
            ]
            headers = ("group_id", "group_name", "description", "是否已同步最新版本")
        else:
            related_groups = [
                (
                    i["group_id"],
                    i["group_name"],
                    i["description"],
                    "无更新" if i["is_lastest"] else "有更新",
                )
                for i in related_groups
            ]
            headers = ("group_id", "group_name", "description", "是否有更新")
        click.echo(tabulate(related_groups, headers=headers))


@group_cli.command("create", help="create group")
@click.option("-n", "--name", required=True, help="name of group")
@click.option("-d", "--description", default="", help="description of group")
@click.option(
    "--is-public", is_flag=True, help="create public config group, default is private"
)
# 保留，向前兼容
@click.option(
    "--kv/--table",
    "is_kv",
    default=True,
    help="(Deprecated, please use --type)",
)
@click.option(
    "-t",
    "--type",
    "type_",
    default="kv",
    help="group type, one of (kv, table, file)",
    type=click.Choice(["kv", "table", "file"]),
)
@click.option(
    "--omit-approval", is_flag=True, help="ignore approval when create release"
)
@click.option(
    "-p",
    "--publish_type",
    default="DEFAULT",
    type=click.Choice(["DEFAULT", "ZHIYAN"]),
    help="publish type for group, default: Default",
)
@click.option(
    "--disable-file-auth", is_flag=True, help="disable auth when group type is file"
)
@click.pass_context
def create_group(
    ctx,
    name,
    description,
    is_public,
    is_kv,
    type_,
    omit_approval,
    publish_type,
    disable_file_auth,
):
    admin = ctx.obj["admin"]
    # 兼容旧版本 is_kv 选项
    if is_kv is False and type_ == "kv":
        type_ = "table"
    admin.create_group(
        name,
        description,
        is_public,
        config_type=type_,
        publish_type=publish_type,
        disable_file_auth=disable_file_auth,
    )
    info("创建成功")
    group = admin[name]
    if omit_approval:
        # create group时 omit_approval 参数不生效，需要update
        group.set_approval(not omit_approval)
    click.echo(
        tabulate(list(zip(GROUP_HEADER, format_group(group))), tablefmt="simple")
    )


@group_cli.command("delete", help="delete group")
@click.argument("group_id_or_name", required=True, nargs=-1)
@click.pass_context
def delete_group(ctx, group_id_or_name):
    admin = ctx.obj["admin"]
    for i in group_id_or_name:
        group = get_group_by_id_or_name(admin, i)
        if group:
            group.delete_group()
            info(f"删除group成功： {group.group_name}")


@group_cli.command("relate", help="relate to public group")
@click.argument("private_group_id_or_name", required=True)
@click.argument("public_group_id_or_name", required=True)
@click.pass_context
def relate(ctx, private_group_id_or_name, public_group_id_or_name):
    admin = ctx.obj["admin"]
    private_group = get_group_by_id_or_name(admin, private_group_id_or_name)
    public_group = get_group_by_id_or_name(admin, public_group_id_or_name)
    if private_group.is_public:
        err(
            f"此group为公共group，不能再关联其他公共group： {private_group.group_id}({private_group.group_name})"
        )
    if not public_group.is_public:
        err(f"被关联的分组为私有group，不能被关联： {public_group.group_id}({public_group.group_name})")
    private_group.relate_public_group(public_group)
    info("关联成功")


@group_cli.command(help="cancel relate to public group")
@click.argument("private_group_id_or_name", required=True)
@click.argument("public_group_id_or_name", required=True)
@click.pass_context
def cancel_relate(ctx, private_group_id_or_name, public_group_id_or_name):
    admin = ctx.obj["admin"]
    private_group = get_group_by_id_or_name(admin, private_group_id_or_name)
    public_group = get_group_by_id_or_name(admin, public_group_id_or_name)
    if private_group.is_public:
        err(
            f"此group为公共group，不能再关联其他公共group： {private_group.group_id}({private_group.group_name})"
        )
    if not public_group.is_public:
        err(
            f"被关联的分组为私有group，不能被解除关联： {public_group.group_id}({public_group.group_name})"
        )
    private_group.cancel_relate(public_group)
    info("解除关联成功")


@group_cli.command(help="sync public group")
@click.argument("private_group_id_or_name", required=True)
@click.argument("public_group_id_or_name", required=True)
@click.pass_context
def sync(ctx, private_group_id_or_name, public_group_id_or_name):
    admin = ctx.obj["admin"]
    private_group = get_group_by_id_or_name(admin, private_group_id_or_name)
    public_group = get_group_by_id_or_name(admin, public_group_id_or_name)
    if private_group.is_public:
        err(
            f"此group为公共group，不能再关联其他公共group： {private_group.group_id}({private_group.group_name})"
        )
    if not public_group.is_public:
        err(
            f"被关联的分组为私有group，不能被解除关联： {public_group.group_id}({public_group.group_name})"
        )
    history_versions = public_group.history_versions
    if not history_versions:
        err("public group don't have released config")
    version = history_versions[0]
    add, delete, update = private_group.sync_from_public(public_group)
    info(
        f"{private_group.group_id}({private_group.group_name}) "
        f"同步public group {public_group.group_id}({public_group.group_name}) "
        f"版本{version['version_name']} 成功"
    )
    from .config import format_config, CONFIG_HEADER

    click.echo("新增key: ")
    click.echo(
        tabulate([format_config(i) for i in add], CONFIG_HEADER, tablefmt="pretty")
    )
    click.echo()
    click.echo("删除key: ")
    click.echo(
        tabulate([format_config(i) for i in delete], CONFIG_HEADER, tablefmt="pretty")
    )
    click.echo()
    click.echo("更新key: ")
    click.echo(
        tabulate([format_config(i) for i in update], CONFIG_HEADER, tablefmt="pretty")
    )


@group_cli.command(help="show group versions")
@click.argument("group_id_or_name", required=True)
@click.pass_context
def versions(ctx, group_id_or_name):
    admin = ctx.obj["admin"]
    group = get_group_by_id_or_name(admin, group_id_or_name)
    data = [
        (
            i["version_id"],
            i["version_name"],
            i["creator"],
            i["description"],
            i["create_time"],
            i["version_uuid"],
        )
        for i in group.history_versions
    ]
    info(f"{group.group_id}({group.group_name}) history versions:")
    click.echo(tabulate(data, VERSION_HEADER, tablefmt="pretty"))


@group_cli.command(help="create release task")
@click.argument("group_id_or_name", required=True)
@click.argument("creator", required=True)
@click.option("--version", help="task version")
@click.option("-d", "--description", help="task description", default="")
@click.option("--updators", help="修改人，指定修改人时，会检查修改人，相当于页面上的 “只能有我的改动”", default="")
@click.option(
    "-f",
    "--format",
    default="str",
    help="result format",
    type=click.Choice(["str", "json"]),
)
@click.pass_context
def create_release(
    ctx, group_id_or_name, creator, version, description, updators, format
):
    admin = ctx.obj["admin"]
    group = get_group_by_id_or_name(admin, group_id_or_name)
    task_id = group.create_release_task(creator, version, description, updators)
    if format == "str":
        info(f"创建发布任务成功，任务id: {task_id}")
    elif format == "json":
        click.echo(json.dumps({"task_id": task_id}))


