@group_cli.command(help="生成版本（开启多版本发布时）")
@click.argument("group_id_or_name", required=True)
@click.option("--version", required=False, help="版本名，留空则自动生成")
@click.option("--creator", required=True, help="发布人，需指定自定义用户名，且自定义用户要有发布权限")
@click.option("--updators", required=False, help="修改人，需要列出本次变动内容的所有修改人")
@click.option("-d", "--description", help="版本描述", default="")
@click.pass_context
def create_config_version(ctx, group_id_or_name, version, creator, updators, description):
    """查看分组当前的消息通知设置"""
    admin = ctx.obj["admin"]
    group = get_group_by_id_or_name(admin, group_id_or_name)
    result = group.create_config_version(
        version_name=version,
        creator=creator,
        updators=updators if updators is not None else creator,
        version_desc=description
    )
    info(f"{result['ret_msg']}")


@group_cli.command(help="创建发布任务（开启多版本发布时）")
@click.argument("group_id_or_name", required=True)
@click.option("--version", required=True, help="已保存的历史版本名")
@click.option("--creator", required=True, help="发布人，需指定自定义用户名，且自定义用户要有发布权限")
@click.option(
    "--target-tags",
    required=True,
    help=r'目标实例标签组合，示例：{"tag1": "a", "tag2": "b"}。{} 代表不区分'
)
@click.option("--approvers", required=False, help="审批人，用;分隔多人")
@click.option("--type", required=False, help="审批方式，0：或签，1：会签", default=0)
@click.option("-d", "--description", help="版本描述", default="")
@click.pass_context
def create_multi_version_release(
        ctx,
        group_id_or_name,
        version,
        creator,
        target_tags,
        approvers,
        type,
        description
):
    """查看分组当前的消息通知设置"""
    admin = ctx.obj["admin"]
    group = get_group_by_id_or_name(admin, group_id_or_name)
    result = group.create_multi_version_release_task(
        creator=creator,
        version_name=version,
        target_tags=target_tags,
        approvers=approvers if approvers is not None else creator,
        type=type,
        desc=description,
    )
    info(f"{result}")
